INSERT INTO resources (name, category_id, subcategory, description, address, city, county, state, zip_code, phone, website, hours, accepts_uninsured, sliding_scale, medicaid, medicare, private_insurance, walk_ins_welcome, appointments, telehealth, cost_free, cost_estimate_min, cost_estimate_max, languages, accessibility, services, specialties, audiences, rating, photo_url, source) VALUES
('Columbia Valley Community Health - East Wenatchee Medical & Dental Clinic', (SELECT id FROM resource_categories WHERE slug='dental'), '', 'FQHC dental clinic offering comprehensive family dental care (children and adults) including exams, cleanings, x-rays, fillings, and urgent care. Saturday hours available. Accepts Medicaid (Apple Health) for adults and children; sliding-fee discounts for the uninsured.', '940 Eastmont Avenue', 'East Wenatchee', 'Douglas', 'WA', '98802', '(509) 662-6000', 'https://cvch.org/location/east-wenatchee-medical-dental-clinic', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, false, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{FQHC dental clinic offering comprehensive family dental care (children and adults) including exams,cleanings,x-rays,fillings,and urgent care}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/3779706/pexels-photo-3779706.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('HealthPoint - Bothell Clinic (Dental)', (SELECT id FROM resource_categories WHERE slug='dental'), '', 'FQHC dental clinic offering routine and preventive dental care, extractions, fillings, crowns, bridges, root canals, and emergency walk-in dental appointments for adults and children. Accepts WA Apple Health (Medicaid), Medicare, and private insurance; sliding-fee scale for the uninsured.', '10414 Beardslee Boulevard, Suite 201', 'Bothell', 'King', 'WA', '98011', '(425) 486-0658', 'https://www.healthpointchc.org/find-clinics/bothell', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, false, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{FQHC dental clinic offering routine and preventive dental care,extractions,fillings,crowns,bridges}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/6642719/pexels-photo-6642719.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Community Health Care - Hilltop Regional Health Center (Dental)', (SELECT id FROM resource_categories WHERE slug='dental'), '', 'FQHC flagship clinic in Tacoma''s Hilltop neighborhood providing comprehensive dental care alongside medical, behavioral health, and pharmacy services. Accepts Apple Health (Medicaid); sliding-fee discounts; no one denied care due to inability to pay.', '1202 Martin Luther King Jr. Way', 'Tacoma', 'Pierce', 'WA', '98405', '(253) 722-2151', 'https://www.commhealth.org/locations', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, false, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{FQHC flagship clinic in Tacoma''s Hilltop neighborhood providing comprehensive dental care alongside medical,behavioral health,and pharmacy services,Accepts Apple Health (Medicaid); sliding-fee discounts; no one denied care due to inability to pay}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/3779706/pexels-photo-3779706.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Seattle Roots Community Health - Dental Clinic', (SELECT id FROM resource_categories WHERE slug='dental'), '', 'FQHC dental clinic on Capitol Hill (home of Carolyn Downs Family Medical Center & Country Doctor Community Clinic). Provides community-driven, culturally appropriate primary and dental healthcare regardless of ability to pay. Accepts Apple Health (Medicaid) and offers sliding-fee scale.', '510 19th Avenue East', 'Seattle', 'King', 'WA', '98112', '(206) 461-4554', 'https://seattleroots.org/clinic/dental-clinic', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, false, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{FQHC dental clinic on Capitol Hill (home of Carolyn Downs Family Medical Center & Country Doctor Community Clinic),Provides community-driven,culturally appropriate primary and dental healthcare regardless of ability to pay,Accepts Apple Health (Medicaid) and offers sliding-fee scale}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/6642719/pexels-photo-6642719.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('988 Suicide & Crisis Lifeline (Washington)', (SELECT id FROM resource_categories WHERE slug='crisis-line'), '', 'Free, confidential, three-digit phone number connecting callers to trained crisis counselors via phone, text, or online chat. Provides 24/7/365 support for those thinking about suicide, experiencing a mental health crisis, concerned about substance use, worried about a loved one, or in need of emotional support. Services in English, Spanish, and interpretation in over 240 additional languages, plus ASL services. Washington State has three designated 988 crisis centers.', 'N/A - Phone Service', 'Statewide', 'Statewide', 'WA', '00000', '988', 'https://wa988.org', '{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}'::jsonb, true, false, false, false, false, true, false, true, true, 0, 0, '{English,Spanish}', '{wheelchair,ADA parking}', '{Free,confidential,three-digit phone number connecting callers to trained crisis counselors via phone,text,or online chat}', '{}', '{Adults,Adolescents}', 4.5, 'https://images.pexels.com/photos/6764920/pexels-photo-6764920.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('King County Regional Crisis Line (Crisis Connections)', (SELECT id FROM resource_categories WHERE slug='crisis-line'), '', 'King County 988 & Regional Crisis Line providing immediate, anonymous, and confidential assistance for people experiencing emotional distress, mental health crisis, or considering suicide. Staffed by trained crisis counselors 24/7/365. Crisis Connections has served the Seattle-King County area for over 50 years and is one of Washington''s three designated 988 crisis centers. Local: 206-461-3222.', 'N/A - Phone Service', 'Statewide', 'King', 'WA', '00000', '866-427-4747', 'https://crisisconnections.org', '{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}'::jsonb, true, false, false, false, false, true, false, true, true, 0, 0, '{English,Spanish}', '{wheelchair,ADA parking}', '{King County 988 & Regional Crisis Line providing immediate,anonymous,and confidential assistance for people experiencing emotional distress,mental health crisis,or considering suicide}', '{}', '{Adults,Adolescents}', 4.5, 'https://images.pexels.com/photos/6678075/pexels-photo-6678075.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Washington Recovery Help Line', (SELECT id FROM resource_categories WHERE slug='crisis-line'), '', 'Statewide, 24-hour service providing emotional support and treatment referrals for individuals struggling with substance use, problem gambling, and mental health disorders. Operated by Crisis Connections and funded by the Washington State Department of Social and Health Services, Division of Behavioral Health and Recovery. Calls are confidential and provide in-the-moment support and connections to local treatment providers. TTY: 206-461-3219.', 'N/A - Phone Service', 'Statewide', 'Statewide', 'WA', '00000', '866-789-1511', 'https://www.warecoveryhelpline.org', '{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}'::jsonb, true, false, false, false, false, true, false, true, true, 0, 0, '{English,Spanish}', '{wheelchair,ADA parking}', '{Statewide,24-hour service providing emotional support and treatment referrals for individuals struggling with substance use,problem gambling,and mental health disorders,Operated by Crisis Connections and funded by the Washington State Department of Social and Health Services}', '{}', '{Adults,Adolescents}', 4.5, 'https://images.pexels.com/photos/6764920/pexels-photo-6764920.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Teen Link (Crisis Connections)', (SELECT id FROM resource_categories WHERE slug='crisis-line'), '', 'Free, anonymous, and confidential helpline ''by teens, for teens'' in Washington State. Calls are answered by trained teen volunteers, supervised by adult mentors. Teens can call, text, or chat about anything on their mind - school stress, friends, family, relationships, identity, or any issue big or small. Also offers school-based suicide prevention education and the ''Where to Turn for Teens'' resource guide. Available 7 days a week, 6:00 PM to 10:00 PM; after-hours referrals to 988.', 'N/A - Phone Service', 'Statewide', 'Statewide', 'WA', '00000', '866-833-6546', 'https://crisisconnections.org/programs/teen-link', '{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}'::jsonb, true, false, false, false, false, true, false, true, true, 0, 0, '{English,Spanish}', '{wheelchair,ADA parking}', '{Free,anonymous,and confidential helpline ''by teens,for teens'' in Washington State,Calls are answered by trained teen volunteers}', '{}', '{Adults,Adolescents}', 4.5, 'https://images.pexels.com/photos/4149199/pexels-photo-4149199.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Veterans Crisis Line', (SELECT id FROM resource_categories WHERE slug='crisis-line'), '', 'Free, confidential, 24/7/365 crisis support service connecting Veterans, service members, National Guard and Reserve members, and their families and friends with qualified, caring VA responders. No enrollment in VA benefits or health care is required. Dial 988 then press 1, or text 838255. The Washington State Department of Veterans Affairs (WDVA) directs veterans to this line.', 'N/A - Phone Service', 'Statewide', 'Statewide', 'WA', '00000', '988', 'https://www.veteranscrisisline.net', '{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}'::jsonb, true, false, false, false, false, true, false, true, true, 0, 0, '{English,Spanish}', '{wheelchair,ADA parking}', '{Free,confidential,24/7/365 crisis support service connecting Veterans,service members,National Guard and Reserve members}', '{}', '{Adults,Adolescents}', 4.5, 'https://images.pexels.com/photos/6678075/pexels-photo-6678075.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Native and Strong Lifeline', (SELECT id FROM resource_categories WHERE slug='crisis-line'), '', 'The nation''s first 988 crisis line designed by and for Indigenous people. Operated by Volunteers of America Western Washington (VOAWW), connecting callers with Native crisis counselors who provide culturally informed support. Created by the Washington State Legislature (HB 1477, 2021) to address disproportionate suicide rates among American Indian and Alaska Native communities. Dial 988 then press 4. Available 24/7/365.', 'N/A - Phone Service', 'Statewide', 'Statewide', 'WA', '00000', '988', 'https://nativeandstrong.org', '{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}'::jsonb, true, false, false, false, false, true, false, true, true, 0, 0, '{English,Spanish}', '{wheelchair,ADA parking}', '{The nation''s first 988 crisis line designed by and for Indigenous people,Operated by Volunteers of America Western Washington (VOAWW),connecting callers with Native crisis counselors who provide culturally informed support,Created by the Washington State Legislature (HB 1477,2021) to address disproportionate suicide rates among American Indian and Alaska Native communities}', '{}', '{Adults,Adolescents}', 4.5, 'https://images.pexels.com/photos/4149199/pexels-photo-4149199.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('WA 211 (Washington 211 Information & Referral)', (SELECT id FROM resource_categories WHERE slug='crisis-line'), '', 'The only statewide helpline in Washington with live, knowledgeable people on the phone and a database of over 17,000 local resources. Free, confidential, multilingual helpline providing one-stop connections to community services including utility assistance, food, housing, healthcare, elder care, childcare, mental health supports, and more. Available 24/7. Toll-free if outside WA or unable to dial 211: 1-877-211-9274. Text: 211WAOD to 898211.', 'N/A - Phone Service', 'Statewide', 'Statewide', 'WA', '00000', '211', 'https://wa211.org', '{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}'::jsonb, true, false, false, false, false, true, false, true, true, 0, 0, '{English,Spanish}', '{wheelchair,ADA parking}', '{The only statewide helpline in Washington with live,knowledgeable people on the phone and a database of over 17,000 local resources,Free,confidential}', '{}', '{Adults,Adolescents}', 4.5, 'https://images.pexels.com/photos/6678075/pexels-photo-6678075.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('National Domestic Violence Hotline', (SELECT id FROM resource_categories WHERE slug='crisis-line'), '', 'Free, confidential, 24/7/365 support via call, chat, or text for anyone experiencing domestic violence or concerned about a loved one. The Washington State Coalition Against Domestic Violence & Sexual Assault refers Washington residents to this hotline. Provides safety planning, resources, and connections to local domestic violence advocacy programs. TTY: 800-787-3224. Deaf Services videophone: 855-812-1001.', 'N/A - Phone Service', 'Statewide', 'Statewide', 'WA', '00000', '800-799-7233', 'https://www.thehotline.org', '{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}'::jsonb, true, false, false, false, false, true, false, true, true, 0, 0, '{English,Spanish}', '{wheelchair,ADA parking}', '{Free,confidential,24/7/365 support via call,chat,or text for anyone experiencing domestic violence or concerned about a loved one}', '{}', '{Adults,Adolescents}', 4.5, 'https://images.pexels.com/photos/6678075/pexels-photo-6678075.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('RAINN National Sexual Assault Hotline', (SELECT id FROM resource_categories WHERE slug='crisis-line'), '', 'Free, confidential, 24/7/365 support via call or chat for survivors of sexual violence. Provides emotional support, information about local resources, and connections to local sexual assault service providers. Recommended by the Washington State Coalition Against Domestic Violence & Sexual Assault and NAMI Seattle as a primary resource for Washington residents.', 'N/A - Phone Service', 'Statewide', 'Statewide', 'WA', '00000', '800-656-4673', 'https://www.rainn.org', '{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}'::jsonb, true, false, false, false, false, true, false, true, true, 0, 0, '{English,Spanish}', '{wheelchair,ADA parking}', '{Free,confidential,24/7/365 support via call or chat for survivors of sexual violence,Provides emotional support,information about local resources}', '{}', '{Adults,Adolescents}', 4.5, 'https://images.pexels.com/photos/4149199/pexels-photo-4149199.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Crisis Connections Warm Line', (SELECT id FROM resource_categories WHERE slug='crisis-line'), '', 'Peer-staffed support line offering a warm, non-crisis alternative for people seeking connection and emotional support. Designed for those who need someone to talk to but are not in an acute crisis. Part of Crisis Connections'' suite of services serving King County and Washington State.', 'N/A - Phone Service', 'Statewide', 'King', 'WA', '00000', '877-500-9276', 'https://crisisconnections.org', '{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}'::jsonb, true, false, false, false, false, true, false, true, true, 0, 0, '{English,Spanish}', '{wheelchair,ADA parking}', '{Peer-staffed support line offering a warm,non-crisis alternative for people seeking connection and emotional support,Designed for those who need someone to talk to but are not in an acute crisis,Part of Crisis Connections'' suite of services serving King County and Washington State}', '{}', '{Adults,Adolescents}', 4.5, 'https://images.pexels.com/photos/6678075/pexels-photo-6678075.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Sundown M Ranch', (SELECT id FROM resource_categories WHERE slug='substance-use'), '', 'Withdrawal management (detox), residential/inpatient SUD treatment for adults and youth (ages 12+), outpatient treatment (Levels I & II), integrated medical services, and family programming. Typical stay 28-45 days. Accepts Apple Health (Medicaid), private insurance, and private pay. Admissions: (800) 326-7444.', '2280 State Route 821', 'Yakima', 'Yakima', 'WA', '98901', '(509) 457-0990', 'https://sundown.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{Withdrawal management (detox),residential/inpatient SUD treatment for adults and youth (ages 12+),outpatient treatment (Levels I & II),integrated medical services,and family programming}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/6759205/pexels-photo-6759205.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Lakeside-Milam Recovery Centers (Kirkland Inpatient)', (SELECT id FROM resource_categories WHERE slug='substance-use'), '', 'CARF-accredited, ASAM-certified. Inpatient residential treatment (4-5 week program) with in-house detox/withdrawal management, ARNP and physician on staff, medication-assisted treatment (MAT), outpatient/IOP at 9 western WA campuses, family programs, mental health services, and ADIS/DACS. Founded 1983. Admissions: (800) 544-1211.', '6725 116th Ave NE, Ste 110', 'Kirkland', 'King', 'WA', '98033', '(425) 822-5095', 'https://lakesidemilam.com', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{CARF-accredited,ASAM-certified,Inpatient residential treatment (4-5 week program) with in-house detox/withdrawal management,ARNP and physician on staff,medication-assisted treatment (MAT)}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/6759205/pexels-photo-6759205.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Pioneer Human Services (Pioneer Counseling - Seattle)', (SELECT id FROM resource_categories WHERE slug='substance-use'), '', 'Nonprofit serving justice-involved individuals. Outpatient SUD counseling, co-occurring residential treatment (King County Residential Treatment Program, 16-bed dual-diagnosis facility), MAT, detox/stabilization services, housing, and employment/training. Headquarters at 7440 W Marginal Way S, Seattle.', '901 Rainier Avenue South', 'Seattle', 'King', 'WA', '98144', '(206) 768-1990', 'https://pioneerhumanservices.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{Nonprofit serving justice-involved individuals,Outpatient SUD counseling,co-occurring residential treatment (King County Residential Treatment Program,16-bed dual-diagnosis facility),MAT}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/6678075/pexels-photo-6678075.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Royal Life Centers at Puget Sound', (SELECT id FROM resource_categories WHERE slug='substance-use'), '', 'Medical detox, residential inpatient treatment for drug and alcohol addiction, individual/group therapy, dual diagnosis care, and aftercare/continuing care.', '1723 Bonney Avenue', 'Sumner', 'Pierce', 'WA', '98390', '(844) 962-2772', 'https://pugetsoundrecoverycenters.com', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{Medical detox,residential inpatient treatment for drug and alcohol addiction,individual/group therapy,dual diagnosis care,and aftercare/continuing care}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/3759079/pexels-photo-3759079.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Royal Life Centers at The Haven', (SELECT id FROM resource_categories WHERE slug='substance-use'), '', 'Medical detoxification, residential inpatient addiction treatment, medication-assisted treatment (MAT), individual and group therapy, psychiatric evaluation, relapse prevention, and aftercare services. Specialized support for veterans.', '1450 Dutter Ave SE', 'Lacey', 'Thurston', 'WA', '98503', '(855) 698-3578', 'https://thehavendetox.com', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{Medical detoxification,residential inpatient addiction treatment,medication-assisted treatment (MAT),individual and group therapy,psychiatric evaluation}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/6759205/pexels-photo-6759205.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Free by the Sea', (SELECT id FROM resource_categories WHERE slug='substance-use'), '', 'CARF-accredited dual-diagnosis treatment center on a 5-acre campus. Residential inpatient, Partial Hospitalization Program (PHP), Intensive Outpatient Program (IOP), medication-assisted treatment (MAT), and gambling addiction track. Accepts private insurance and ITU funds.', '25517 Park Avenue', 'Ocean Park', 'Pacific', 'WA', '98640', '(360) 777-7050', 'https://freebythesea.com', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{CARF-accredited dual-diagnosis treatment center on a 5-acre campus,Residential inpatient,Partial Hospitalization Program (PHP),Intensive Outpatient Program (IOP),medication-assisted treatment (MAT)}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/6678075/pexels-photo-6678075.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified') ON CONFLICT DO NOTHING;INSERT INTO resources (name, category_id, subcategory, description, address, city, county, state, zip_code, phone, website, hours, accepts_uninsured, sliding_scale, medicaid, medicare, private_insurance, walk_ins_welcome, appointments, telehealth, cost_free, cost_estimate_min, cost_estimate_max, languages, accessibility, services, specialties, audiences, rating, photo_url, source) VALUES
('Spokane Treatment & Recovery Services (STARS)', (SELECT id FROM resource_categories WHERE slug='substance-use'), '', 'Non-profit behavioral health agency serving the Inland Northwest since 1980. SUD and mental health assessments, sobering/triage, withdrawal management, women''s residential (Karen''s House), men''s residential (Cub House), co-occurring intensive outpatient, and case management. 24/7 SUD services.', '105 W. 3rd Avenue', 'Spokane', 'Spokane', 'WA', '99201', '(509) 570-7250', 'https://spokanerecovery.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{Non-profit behavioral health agency serving the Inland Northwest since 1980,SUD and mental health assessments,sobering/triage,withdrawal management,women''s residential (Karen''s House)}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/6759205/pexels-photo-6759205.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Spokane Falls Recovery Center', (SELECT id FROM resource_categories WHERE slug='substance-use'), '', 'Joint Commission-accredited. Medical detox, residential treatment (24-hour medical supervision), Partial Hospitalization Program (PHP), Intensive Outpatient Program (IOP), standard outpatient, and assessments. ASAM-aligned evidence-based modalities.', '101 East Magnesium Road, Ste 101', 'Spokane', 'Spokane', 'WA', '99208', '(509) 368-9021', 'https://www.spokanefallsrecoverycenter.com', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{Joint Commission-accredited,Medical detox,residential treatment (24-hour medical supervision),Partial Hospitalization Program (PHP),Intensive Outpatient Program (IOP)}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/6678075/pexels-photo-6678075.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Spokane Addiction Recovery Centers (SAR)', (SELECT id FROM resource_categories WHERE slug='substance-use'), '', 'Outpatient substance use disorder treatment, assessments, and continuing care. SAR is the operating name of the organization historically incorporated as Inland Empire Recovery Centers. Accepts Medicaid and private insurance. Outpatient clinic at 1508 W. 6th Avenue.', '812 S Walnut St', 'Spokane', 'Spokane', 'WA', '99204', '(509) 624-5228', 'https://www.sarc.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{Outpatient substance use disorder treatment,assessments,and continuing care,SAR is the operating name of the organization historically incorporated as Inland Empire Recovery Centers,Accepts Medicaid and private insurance}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/6678075/pexels-photo-6678075.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Inland Northwest Behavioral Health', (SELECT id FROM resource_categories WHERE slug='substance-use'), '', '100-bed inpatient psychiatric hospital (operated by UHS). Mental health and co-occurring substance use assessment and treatment for adults and adolescents, inpatient stabilization, and dual-diagnosis care. Walk-in assessments; accepts Apple Health (Medicaid) and most insurances. Spokane Valley branch at 924 S Pines Rd, Suite 101.', '104 West 5th Avenue', 'Spokane', 'Spokane', 'WA', '99204', '(509) 992-1888', 'https://inlandnorthwestbh.com', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{100-bed inpatient psychiatric hospital (operated by UHS),Mental health and co-occurring substance use assessment and treatment for adults and adolescents,inpatient stabilization,and dual-diagnosis care,Walk-in assessments; accepts Apple Health (Medicaid) and most insurances}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/6678075/pexels-photo-6678075.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Sequoia Detox Centers (Sequoia Recovery Centers)', (SELECT id FROM resource_categories WHERE slug='substance-use'), '', 'Joint Commission-accredited. Full continuum of care: medical detoxification, residential inpatient treatment, outpatient programs, dual-diagnosis care, and aftercare. Individualized withdrawal management.', '10305 East Montgomery Drive', 'Spokane Valley', 'Spokane', 'WA', '99206', '(509) 418-2108', 'https://sequoiadetoxcenters.com', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{Joint Commission-accredited,Full continuum of care: medical detoxification,residential inpatient treatment,outpatient programs,dual-diagnosis care}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/3759079/pexels-photo-3759079.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Spokane Regional Health District - Opioid Treatment Program', (SELECT id FROM resource_categories WHERE slug='substance-use'), '', 'State- and federally-accredited Opioid Treatment Program (OTP). Medication-Assisted Treatment (MAT/MOUD) with methadone and buprenorphine, individual and group counseling, on-site mental health counseling, yearly health physicals, and case management. Sliding fee schedule; accepts Medicaid, Medicare, and most commercial plans. Ages 18+.', '312 W. Eighth Avenue', 'Spokane', 'Spokane', 'WA', '99204', '(509) 324-1420', 'https://srhd.org/programs-and-services/opioid-treatment-program', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{State- and federally-accredited Opioid Treatment Program (OTP),Medication-Assisted Treatment (MAT/MOUD) with methadone and buprenorphine,individual and group counseling,on-site mental health counseling,yearly health physicals}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/3759079/pexels-photo-3759079.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Cedar Wellness Center', (SELECT id FROM resource_categories WHERE slug='substance-use'), '', 'Opioid Treatment Program (methadone clinic). MAT for fentanyl, heroin, prescription opioids, and other substance use disorders (methamphetamine, benzodiazepines, cocaine, alcohol). Integrated mental health services for dual-diagnosis patients, limited primary/urgent care for enrolled patients, individual and group therapy, and patient navigation. Walk-ins welcome 7 days/week. Accepts Medicaid and Medicare.', '503 E 26th Street', 'Tacoma', 'Pierce', 'WA', '98421', '(253) 881-7001', 'https://cw.health', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{Opioid Treatment Program (methadone clinic),MAT for fentanyl,heroin,prescription opioids,and other substance use disorders (methamphetamine}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/6759205/pexels-photo-6759205.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Northwest Harvest - SODO Community Market', (SELECT id FROM resource_categories WHERE slug='food-bank'), '', 'No-cost client-choice grocery store open Monday, Wednesday, and Friday. Provides fresh produce, grocery staples, and healthy food options to anyone in need, along with on-site healthcare, housing, and legal resource services. Operated by Northwest Harvest, Washington State''s leading food justice organization. Main line: (800) 722-6924.', '1915 4th Ave S', 'Seattle', 'King', 'WA', '98134', '(206) 625-0755', 'https://www.northwestharvest.org/our-work/community-programs/sodo-community-market', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, false, false, false, false, true, true, false, true, 0, 0, '{English,Spanish}', '{wheelchair,ADA parking}', '{No-cost client-choice grocery store open Monday,Wednesday,and Friday,Provides fresh produce,grocery staples}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/6192363/pexels-photo-6192363.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Food Lifeline - Hunger Solution Center', (SELECT id FROM resource_categories WHERE slug='food-bank'), '', 'Western Washington''s largest food rescue and distribution organization, serving 17 counties and over 250 food bank partners. Provides community food distributions, mobile markets with culturally relevant foods, and acts as a warehouse/distribution hub for partner agencies. Toll-free: 1-877-404-7543.', '815 S 96th St', 'Seattle', 'King', 'WA', '98108', '(206) 545-6600', 'https://foodlifeline.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, false, false, false, false, true, true, false, true, 0, 0, '{English,Spanish}', '{wheelchair,ADA parking}', '{Western Washington''s largest food rescue and distribution organization,serving 17 counties and over 250 food bank partners,Provides community food distributions,mobile markets with culturally relevant foods,and acts as a warehouse/distribution hub for partner agencies}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/6646917/pexels-photo-6646917.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Ballard Food Bank', (SELECT id FROM resource_categories WHERE slug='food-bank'), '', 'Provides client-choice food shopping, home delivery, weekend food for kids, a Kindness Cafe, ''no-cook'' bags for those without kitchen access, and a Resource Hub offering help with IDs, mail, and financial assistance. Serves the Ballard and north Seattle community.', '1400 NW Leary Way', 'Seattle', 'King', 'WA', '98107', '(206) 789-7800', 'https://www.ballardfoodbank.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, false, false, false, false, true, true, false, true, 0, 0, '{English,Spanish}', '{wheelchair,ADA parking}', '{Provides client-choice food shopping,home delivery,weekend food for kids,a Kindness Cafe,''no-cook'' bags for those without kitchen access}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/6192363/pexels-photo-6192363.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('North Helpline - Lake City Food Bank', (SELECT id FROM resource_categories WHERE slug='food-bank'), '', 'Client-choice in-person food shopping in Lake City on Wednesdays, Thursdays, and Saturdays (second site at 13000 Linden Ave N, Bitter Lake). Also offers homelessness prevention services including rent, utility, and financial assistance.', '12736 33rd Ave NE, Suite 100', 'Seattle', 'King', 'WA', '98125', '(206) 367-3477', 'https://northhelpline.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, false, false, false, false, true, true, false, true, 0, 0, '{English,Spanish}', '{wheelchair,ADA parking}', '{Client-choice in-person food shopping in Lake City on Wednesdays,Thursdays,and Saturdays (second site at 13000 Linden Ave N,Bitter Lake),Also offers homelessness prevention services including rent}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/4252140/pexels-photo-4252140.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Bellingham Food Bank', (SELECT id FROM resource_categories WHERE slug='food-bank'), '', 'Serving Whatcom County since 1972, this is the warehouse hub for the Whatcom County Food Bank Network. Offers a free grocery program (Mon/Wed/Fri 10am-6pm), a drive-through pickup program (Tuesdays with reservation), and a home delivery program (Fridays). Handles approximately 5,000 household visits per week.', '1824 Ellis St', 'Bellingham', 'Whatcom', 'WA', '98225', '(360) 676-0392', 'https://www.bellinghamfoodbank.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, false, false, false, false, true, true, false, true, 0, 0, '{English,Spanish}', '{wheelchair,ADA parking}', '{Serving Whatcom County since 1972,this is the warehouse hub for the Whatcom County Food Bank Network,Offers a free grocery program (Mon/Wed/Fri 10am-6pm),a drive-through pickup program (Tuesdays with reservation),and a home delivery program (Fridays)}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/4252140/pexels-photo-4252140.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Second Harvest - Spokane Hunger Solution Center', (SELECT id FROM resource_categories WHERE slug='food-bank'), '', 'The Inland Northwest''s major food distribution organization, serving 21 Eastern Washington counties and 5 North Idaho counties through a network of partner food banks, meal sites, and high-need schools. Clients are directed to partner neighborhood food banks via the ''Find Food'' page. Also operates the Wolff Family Child Hunger Solution Center and a Tri-Cities location.', '1234 E Front Ave', 'Spokane', 'Spokane', 'WA', '99202', '(509) 534-6678', 'https://2-harvest.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, false, false, false, false, true, true, false, true, 0, 0, '{English,Spanish}', '{wheelchair,ADA parking}', '{The Inland Northwest''s major food distribution organization,serving 21 Eastern Washington counties and 5 North Idaho counties through a network of partner food banks,meal sites,and high-need schools,Clients are directed to partner neighborhood food banks via the ''Find Food'' page}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/6192363/pexels-photo-6192363.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Thurston County Food Bank - Olympia Food Pantry', (SELECT id FROM resource_categories WHERE slug='food-bank'), '', 'Operates multiple pantries across Olympia, Lacey, Tumwater, and surrounding areas, including a Lacey Food Pantry at 7027 Martin Way E. Provides emergency food and operates ''The Other Bank'' (toiletries/household items) Mon/Wed/Fri 10:30am-3:00pm. Also runs mobile food bank services.', '220 Thurston Ave NE', 'Olympia', 'Thurston', 'WA', '98501', '(360) 352-8597', 'https://tcfb.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, false, false, false, false, true, true, false, true, 0, 0, '{English,Spanish}', '{wheelchair,ADA parking}', '{Operates multiple pantries across Olympia,Lacey,Tumwater,and surrounding areas,including a Lacey Food Pantry at 7027 Martin Way E}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/2611817/pexels-photo-2611817.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Yakima Rotary Food Bank', (SELECT id FROM resource_categories WHERE slug='food-bank'), '', 'Serving the Yakima community since 1971, located at the corner of Central Ave & South 7th Street next to the Henry Beauchamp Community Center. Provides nutritious food to anyone who needs it - no ID or documentation required. Serves over 600 families weekly (Friday distribution 8am-12pm).', '703 Central Ave', 'Yakima', 'Yakima', 'WA', '98901', '(509) 853-8918', 'https://yakimarotaryfoodbank.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, false, false, false, false, true, true, false, true, 0, 0, '{English,Spanish}', '{wheelchair,ADA parking}', '{Serving the Yakima community since 1971,located at the corner of Central Ave & South 7th Street next to the Henry Beauchamp Community Center,Provides nutritious food to anyone who needs it - no ID or documentation required,Serves over 600 families weekly (Friday distribution 8am-12pm)}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/2611817/pexels-photo-2611817.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('St. Leo Food Connection', (SELECT id FROM resource_categories WHERE slug='food-bank'), '', 'One of the largest emergency food pantries in Pierce County. Open Wed/Thu/Fri (closed first Thursday of each month), serving 140,000+ client visits annually. Also operates the Springbrook Mobile Food Bank and St. Charles Borromeo Food Bank.', '1323 S Yakima Ave', 'Tacoma', 'Pierce', 'WA', '98405', '(253) 383-5048', 'https://foodconnection.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, false, false, false, false, true, true, false, true, 0, 0, '{English,Spanish}', '{wheelchair,ADA parking}', '{One of the largest emergency food pantries in Pierce County,Open Wed/Thu/Fri (closed first Thursday of each month),serving 140,000+ client visits annually,Also operates the Springbrook Mobile Food Bank and St}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/4252140/pexels-photo-4252140.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Nourish Pierce County (formerly FISH Food Banks of Pierce County)', (SELECT id FROM resource_categories WHERE slug='food-bank'), '', 'Pierce County''s largest food bank network, operating approximately 25 neighborhood food bank sites plus mobile food banks. Clients may visit one site weekly. All guests are asked for name, household size, address/zip, and household members'' dates of birth - but no one in need is turned away. Address shown is the SE Tacoma Nourish location (Mon-Sat 11am-6pm); see website for the full site locator.', '1704 E 85th St', 'Tacoma', 'Pierce', 'WA', '98404', '(253) 383-3164', 'https://nourishpc.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, false, false, false, false, true, true, false, true, 0, 0, '{English,Spanish}', '{wheelchair,ADA parking}', '{Pierce County''s largest food bank network,operating approximately 25 neighborhood food bank sites plus mobile food banks,Clients may visit one site weekly,All guests are asked for name,household size}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/4252140/pexels-photo-4252140.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Fife-Milton Food Bank', (SELECT id FROM resource_categories WHERE slug='food-bank'), '', 'A ministry of St. Martin of Tours Parish since 1992, serving the Fife, Milton, and Edgewood communities. Open for walk-ups, drive-ups, or appointments 9am-1pm on Mondays, Tuesdays, and Thursdays. Clients are encouraged to call ahead.', '2303 54th Ave E', 'Fife', 'Pierce', 'WA', '98424', '(253) 922-0960', 'https://www.fife-milton-food-bank.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, false, false, false, false, true, true, false, true, 0, 0, '{English,Spanish}', '{wheelchair,ADA parking}', '{A ministry of St,Martin of Tours Parish since 1992,serving the Fife,Milton,and Edgewood communities}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/6646917/pexels-photo-6646917.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Sumner Community Food Bank', (SELECT id FROM resource_categories WHERE slug='food-bank'), '', 'Volunteer-based, non-profit food bank operating since 1985. Provides healthy fresh and packaged foods, beverages, pet food, childcare items, and personal hygiene products. Serves the Sumner area, with outreach into both King and Pierce counties. By-appointment service model - registration required to access. Inclusive to all individuals regardless of religion, race, national origin, age, sex, or disability.', '15625 Main St E', 'Sumner', 'Pierce', 'WA', '98390', '(253) 863-3793', 'https://www.sumnerfoodbank.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, false, false, false, false, true, true, false, true, 0, 0, '{English,Spanish}', '{wheelchair,ADA parking}', '{Volunteer-based,non-profit food bank operating since 1985,Provides healthy fresh and packaged foods,beverages,pet food}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/4252140/pexels-photo-4252140.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Gig Harbor Peninsula FISH Food Bank & Community Services', (SELECT id FROM resource_categories WHERE slug='food-bank'), '', 'Independent, volunteer-led 501(c)(3) nonprofit founded in 1976, providing food and emergency assistance with dignity to greater Gig Harbor, Fox Island, the Key Peninsula, and a portion of southernmost Kitsap County. Food bank hours: Mon/Fri 9:30am-3pm, Wed/Thu 9:30am-5:30pm. Financial aid: (253) 851-8800.', '4303 Burnham Dr', 'Gig Harbor', 'Pierce', 'WA', '98332', '(253) 858-6179', 'https://www.ghpfish.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, false, false, false, false, true, true, false, true, 0, 0, '{English,Spanish}', '{wheelchair,ADA parking}', '{Independent,volunteer-led 501(c)(3) nonprofit founded in 1976,providing food and emergency assistance with dignity to greater Gig Harbor,Fox Island,the Key Peninsula}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/4252140/pexels-photo-4252140.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified') ON CONFLICT DO NOTHING;INSERT INTO resources (name, category_id, subcategory, description, address, city, county, state, zip_code, phone, website, hours, accepts_uninsured, sliding_scale, medicaid, medicare, private_insurance, walk_ins_welcome, appointments, telehealth, cost_free, cost_estimate_min, cost_estimate_max, languages, accessibility, services, specialties, audiences, rating, photo_url, source) VALUES
('Eloise''s Cooking Pot Food Bank', (SELECT id FROM resource_categories WHERE slug='food-bank'), '', 'Community food bank in east Tacoma providing groceries to individuals and families in need. Open Tuesday-Saturday, 10:30am-4pm. Operated by the Making a Difference Foundation, focused on serving underserved communities in the Tacoma area.', '3543 E McKinley Ave', 'Tacoma', 'Pierce', 'WA', '98404', '(253) 426-1994', 'https://themadf.org/eloises-cooking-pot', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, false, false, false, false, true, true, false, true, 0, 0, '{English,Spanish}', '{wheelchair,ADA parking}', '{Community food bank in east Tacoma providing groceries to individuals and families in need,Open Tuesday-Saturday,10:30am-4pm,Operated by the Making a Difference Foundation,focused on serving underserved communities in the Tacoma area}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/6646917/pexels-photo-6646917.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Henry Beauchamp Community Center (Food Pantry)', (SELECT id FROM resource_categories WHERE slug='food-bank'), '', 'Community center in east Yakima adjacent to the Yakima Rotary Food Bank, offering a Monday food pantry program along with youth and community services. Serves the east Yakima neighborhood, which has some of the highest food insecurity rates in the county.', '1211 S 7th St', 'Yakima', 'Yakima', 'WA', '98901', '(509) 575-6114', 'https://www.yakimacounty.us/3101/Food-Banks', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, false, false, false, false, true, true, false, true, 0, 0, '{English,Spanish}', '{wheelchair,ADA parking}', '{Community center in east Yakima adjacent to the Yakima Rotary Food Bank,offering a Monday food pantry program along with youth and community services,Serves the east Yakima neighborhood,which has some of the highest food insecurity rates in the county}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/4252140/pexels-photo-4252140.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('United Way of King County', (SELECT id FROM resource_categories WHERE slug='community-org'), '', 'Mobilizes communities to advance the common good in the areas of youth opportunity, healthy community, financial security, and community resiliency. Direct services include rental assistance, transitional goods, financial education, tax preparation help, and funding support for local health and human service programs. Founded in 1921.', '720 Second Avenue', 'Seattle', 'King', 'WA', '98104', '(206) 461-3700', 'https://www.uwkc.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, false, false, false, false, true, true, false, true, 0, 0, '{English,Spanish}', '{wheelchair,ADA parking}', '{Mobilizes communities to advance the common good in the areas of youth opportunity,healthy community,financial security,and community resiliency,Direct services include rental assistance}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/3184360/pexels-photo-3184360.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Catholic Community Services of Western Washington (CCSWW)', (SELECT id FROM resource_categories WHERE slug='community-org'), '', 'The largest private social services provider in Western Washington, serving all 19 counties west of the Cascades. Services include housing and homeless services, family behavioral health services, long-term care for seniors and people with disabilities, PREPARES (childbirth and parenting support), food assistance, and immigration legal services.', '100 23rd Avenue South', 'Seattle', 'King', 'WA', '98144', '(206) 328-5696', 'https://ccsww.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, false, false, false, false, true, true, false, true, 0, 0, '{English,Spanish}', '{wheelchair,ADA parking}', '{The largest private social services provider in Western Washington,serving all 19 counties west of the Cascades,Services include housing and homeless services,family behavioral health services,long-term care for seniors and people with disabilities}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/3184292/pexels-photo-3184292.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Catholic Charities Serving Eastern Washington (CCEW)', (SELECT id FROM resource_categories WHERE slug='community-org'), '', 'Founded in 1912, the oldest and largest provider of social services and housing in Eastern Washington, serving 13 counties and more than 72,000 community members annually. Programs include the House of Charity 24/7 emergency shelter, Rising Strong family drug treatment program, St. Margaret''s Shelter for families, Catholic Housing Communities for low-income seniors and chronically homeless individuals, senior/chore services, Food for All, immigration legal services, counseling, and the St. Anne''s Children & Family Center.', '12 East 5th Avenue', 'Spokane', 'Spokane', 'WA', '99202', '(509) 358-4250', 'https://www.cceasternwa.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, false, false, false, false, true, true, false, true, 0, 0, '{English,Spanish}', '{wheelchair,ADA parking}', '{Founded in 1912,the oldest and largest provider of social services and housing in Eastern Washington,serving 13 counties and more than 72,000 community members annually,Programs include the House of Charity 24/7 emergency shelter}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/3184465/pexels-photo-3184465.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('The Salvation Army - Seattle Social Services', (SELECT id FROM resource_categories WHERE slug='community-org'), '', 'Provides a comprehensive suite of social services including a food bank, emergency financial assistance, shelter, utility assistance, and seasonal/holiday assistance. The Seattle Social Services office on Pike Street is the primary downtown service location.', '1101 Pike Street', 'Seattle', 'King', 'WA', '98101', '(206) 447-9944', 'https://seattle.salvationarmy.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, false, false, false, false, true, true, false, true, 0, 0, '{English,Spanish}', '{wheelchair,ADA parking}', '{Provides a comprehensive suite of social services including a food bank,emergency financial assistance,shelter,utility assistance,and seasonal/holiday assistance}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/3184292/pexels-photo-3184292.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Solid Ground', (SELECT id FROM resource_categories WHERE slug='community-org'), '', 'Anti-poverty organization that addresses the root causes of homelessness and poverty. Programs include tenant services/eviction prevention, the Statewide Poverty Action Network (advocacy), housing and homelessness services, food resources, transportation assistance, and the Solid Ground HomeLine.', '1501 North 45th Street', 'Seattle', 'King', 'WA', '98103', '(206) 694-6700', 'https://www.solid-ground.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, false, false, false, false, true, true, false, true, 0, 0, '{English,Spanish}', '{wheelchair,ADA parking}', '{Anti-poverty organization that addresses the root causes of homelessness and poverty,Programs include tenant services/eviction prevention,the Statewide Poverty Action Network (advocacy),housing and homelessness services,food resources}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/3184360/pexels-photo-3184360.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('YWCA Seattle | King | Snohomish', (SELECT id FROM resource_categories WHERE slug='community-org'), '', 'Founded in 1894, works to eliminate racism and empower women. Each year serves nearly 50,000 people through housing and homelessness prevention, employment and economic advancement services, domestic violence support, health and wellness programs, youth services, and early childhood education.', '1118 Fifth Avenue', 'Seattle', 'King', 'WA', '98101', '(206) 461-4888', 'https://www.ywcaworks.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, false, false, false, false, true, true, false, true, 0, 0, '{English,Spanish}', '{wheelchair,ADA parking}', '{Founded in 1894,works to eliminate racism and empower women,Each year serves nearly 50,000 people through housing and homelessness prevention,employment and economic advancement services}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/3184325/pexels-photo-3184325.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Multi-Service Center (MSC)', (SELECT id FROM resource_categories WHERE slug='community-org'), '', 'Helps families and individuals with low to moderate incomes build lasting change through programs including food banks and emergency food, emergency shelters and motel vouchers, rental/mortgage assistance and homelessness prevention, energy/utility assistance, affordable and permanent supportive housing, employment services, youth and young adult services, Head Start and after-school programs, and a long-term care ombudsman program.', '1200 South 336th Street', 'Federal Way', 'King', 'WA', '98003', '(253) 838-6810', 'https://mschelps.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, false, false, false, false, true, true, false, true, 0, 0, '{English,Spanish}', '{wheelchair,ADA parking}', '{Helps families and individuals with low to moderate incomes build lasting change through programs including food banks and emergency food,emergency shelters and motel vouchers,rental/mortgage assistance and homelessness prevention,energy/utility assistance,affordable and permanent supportive housing}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/3184360/pexels-photo-3184360.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Byrd Barr Place', (SELECT id FROM resource_categories WHERE slug='community-org'), '', 'Founded in 1964 as the Central Area Motivation Program (CAMP), a community action agency based in Seattle''s Central District (historic Fire Station #23, listed on the National Register of Historic Places). Provides essential services including food bank/food assistance, housing and energy/utility assistance, and financial education and tools for Seattle residents.', '722 18th Avenue', 'Seattle', 'King', 'WA', '98122', '(206) 812-4940', 'https://byrdbarrplace.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, false, false, false, false, true, true, false, true, 0, 0, '{English,Spanish}', '{wheelchair,ADA parking}', '{Founded in 1964 as the Central Area Motivation Program (CAMP),a community action agency based in Seattle''s Central District (historic Fire Station #23,listed on the National Register of Historic Places),Provides essential services including food bank/food assistance,housing and energy/utility assistance}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/3184325/pexels-photo-3184325.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Neighborhood House', (SELECT id FROM resource_categories WHERE slug='community-org'), '', 'Founded in 1906, builds community and increases access to housing, health, education, and economic opportunity. Working with over 13,000 people each year, services focus on immigrants, refugees, low-income community members, and public housing residents. Program areas include aging and disability services, community health, early childhood education, employment and adult education, housing and eviction prevention assistance, and youth and family services. Operates from more than 15 sites throughout King County.', '1225 South Weller Street, Suite 510', 'Seattle', 'King', 'WA', '98144', '(206) 923-6480', 'https://nhwa.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, false, false, false, false, true, true, false, true, 0, 0, '{English,Spanish}', '{wheelchair,ADA parking}', '{Founded in 1906,builds community and increases access to housing,health,education,and economic opportunity}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/3184465/pexels-photo-3184465.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('El Centro de la Raza', (SELECT id FROM resource_categories WHERE slug='community-org'), '', 'Founded in 1972, a voice and hub for the Latino/a community in Seattle and King County, serving people of all races. Provides 43 programs and services for children, youth, families, and seniors, organized into nine service areas that include the Jose Marti Child Development Center, housing and homelessness services, immigration legal services, employment and adult education, health and wellness programs, civic engagement, and senior services. The organization''s mission centers on building the Beloved Community, undoing systemic racism, and ending poverty.', '2524 16th Avenue South', 'Seattle', 'King', 'WA', '98144', '(206) 957-4634', 'https://www.elcentrodelaraza.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, false, false, false, false, true, true, false, true, 0, 0, '{English,Spanish}', '{wheelchair,ADA parking}', '{Founded in 1972,a voice and hub for the Latino/a community in Seattle and King County,serving people of all races,Provides 43 programs and services for children,youth}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/3184360/pexels-photo-3184360.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Hopelink - Medicaid Transportation (NEMT Broker)', (SELECT id FROM resource_categories WHERE slug='transportation'), '', 'Official Washington State HCA-contracted broker for Non-Emergency Medical Transportation (NEMT) in King and Snohomish Counties. Arranges rides (rideshare, van, mileage reimbursement, gas vouchers, ferry fares) for Medicaid/Apple Health clients to Medicaid-covered medical, dental, and mental health appointments. Snohomish County: 1-855-766-7433. TDD/TTY: 1-800-246-1646. General office: (425) 869-6000.', '8990 154th Avenue NE', 'Redmond', 'King', 'WA', '98052', '1-800-923-7433', 'https://www.hopelink.org/programs/medicaid-transportation', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, false, false, false, false, false, true, false, true, 0, 0, '{English,Spanish}', '{wheelchair,ADA parking}', '{Official Washington State HCA-contracted broker for Non-Emergency Medical Transportation (NEMT) in King and Snohomish Counties,Arranges rides (rideshare,van,mileage reimbursement,gas vouchers}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/97079/pexels-photo-97079.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Paratransit Services - WA State NEMT Broker', (SELECT id FROM resource_categories WHERE slug='transportation'), '', 'Washington State''s original NEMT broker, contracted by the WA Health Care Authority to broker Non-Emergency Medical Transportation for Medicaid/Apple Health recipients in nine counties: Clallam, Jefferson, Kitsap, Pierce, Mason, Thurston, Lewis, Grays Harbor, and Pacific. Arranges the lowest-cost appropriate mode (bus, taxi, wheelchair van, gas reimbursement, ferry tickets) to Medicaid-covered appointments. NEMT portal: https://www.wanemt.com. TDD/TTY: 1-800-934-5438.', '4810 Auto Center Way, Suite Z', 'Bremerton', 'Kitsap', 'WA', '98312', '1-800-756-5438', 'https://www.paratransit.net/nemtbrokerage', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, false, false, false, false, false, true, false, true, 0, 0, '{English,Spanish}', '{wheelchair,ADA parking}', '{Washington State''s original NEMT broker,contracted by the WA Health Care Authority to broker Non-Emergency Medical Transportation for Medicaid/Apple Health recipients in nine counties: Clallam,Jefferson,Kitsap,Pierce}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/1058622/pexels-photo-1058622.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('People for People (PFP) Transportation - Medicaid NEMT Broker', (SELECT id FROM resource_categories WHERE slug='transportation'), '', 'HCA-contracted Medicaid NEMT broker for Yakima, Kittitas, Chelan, Douglas, Okanogan, Benton, Franklin, Columbia, and Walla Walla Counties. Provides Medicaid-eligible trip coordination (mileage reimbursement, gas vouchers, ride assignment), as well as fare-free door-to-door paratransit for older adults (60+), low-income households, youth, persons with disabilities, and veterans in Adams, Grant, Lincoln, and Yakima counties. Also operates fare-free Community Connector fixed routes across multiple Eastern WA counties. General office: (509) 248-6726. TDD/TTY: 800-606-1302.', '304 W. Lincoln Ave', 'Yakima', 'Yakima', 'WA', '98902', '1-800-233-1624', 'https://www.mypfp.org/services/transportation', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, false, false, false, false, false, true, false, true, 0, 0, '{English,Spanish}', '{wheelchair,ADA parking}', '{HCA-contracted Medicaid NEMT broker for Yakima,Kittitas,Chelan,Douglas,Okanogan}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/1058622/pexels-photo-1058622.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('King County Metro - Access Paratransit', (SELECT id FROM resource_categories WHERE slug='transportation'), '', 'ADA-complementary paratransit service for King County residents whose disability prevents them from independently using regular accessible fixed-route bus and light rail service. Provides shared-ride, curb-to-curb transportation in lift-equipped accessible vans within 3/4 mile of King County Metro fixed routes during the same hours. Eligibility requires an application, healthcare professional verification, and an in-person functional evaluation. One-way fare $1.75; monthly pass $63. Personal care attendant rides free if certified. Access reservations: 1-866-205-5001. Eligibility: (206) 263-3113. WA Relay: 711.', '201 S. Jackson Street, King Street Center', 'Seattle', 'King', 'WA', '98104', '(206) 205-5000', 'https://kingcounty.gov/depts/metro/transportation-options/accessible-services.aspx', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, false, false, false, false, false, true, false, true, 0, 0, '{English,Spanish}', '{wheelchair,ADA parking}', '{ADA-complementary paratransit service for King County residents whose disability prevents them from independently using regular accessible fixed-route bus and light rail service,Provides shared-ride,curb-to-curb transportation in lift-equipped accessible vans within 3/4 mile of King County Metro fixed routes during the same hours,Eligibility requires an application,healthcare professional verification}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/1058622/pexels-photo-1058622.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Pierce Transit - SHUTTLE (ADA Paratransit)', (SELECT id FROM resource_categories WHERE slug='transportation'), '', 'Pierce Transit''s ADA Paratransit SHUTTLE is a shared-ride, door-to-door service for individuals in Pierce County who, because of a disability, are unable to ride a regular fixed-route Pierce Transit bus. Eligibility follows the Americans with Disabilities Act (ADA) of 1990 standards and is determined through an application and possible in-person functional assessment. Service area mirrors 3/4-mile corridors around Pierce Transit fixed routes. Also offers free Travel Training to help seniors and people with disabilities learn to use the fixed-route bus system. Toll-free: 1-800-841-1118. TTY: 711.', '3701 96th St. SW', 'Lakewood', 'Pierce', 'WA', '98499', '(253) 581-8000', 'https://piercetransit.org/paratransit/', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, false, false, false, false, false, true, false, true, 0, 0, '{English,Spanish}', '{wheelchair,ADA parking}', '{Pierce Transit''s ADA Paratransit SHUTTLE is a shared-ride,door-to-door service for individuals in Pierce County who,because of a disability,are unable to ride a regular fixed-route Pierce Transit bus,Eligibility follows the Americans with Disabilities Act (ADA) of 1990 standards and is determined through an application and possible in-person functional assessment}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/97079/pexels-photo-97079.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Ben Franklin Transit - Dial-A-Ride (ADA Paratransit)', (SELECT id FROM resource_categories WHERE slug='transportation'), '', 'Ben Franklin Transit (BFT) provides public transportation for the Tri-Cities area (Kennewick, Pasco, Richland, West Richland, Benton City, Prosser, Finley). Dial-A-Ride is the ADA paratransit complementary service offering specialized door-to-door transportation for individuals with disabilities who cannot use the fixed-route bus system. Fares: $1.50 per boarding within 3/4 mile of a fixed route; $3.00 fare beyond 3/4 mile. BFT also operates fixed-route buses, the CONNECT/Tri-Cities on-demand service, and a Rideshare program. Dial-A-Ride Reservations: (509) 735-0160. ADA Eligibility Coordinator: (509) 734-5530.', '1000 Columbia Park Trail', 'Richland', 'Benton', 'WA', '99352', '(509) 735-5100', 'https://www.bft.org/dial-a-ride', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, false, false, false, false, false, true, false, true, 0, 0, '{English,Spanish}', '{wheelchair,ADA parking}', '{Ben Franklin Transit (BFT) provides public transportation for the Tri-Cities area (Kennewick,Pasco,Richland,West Richland,Benton City}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/97079/pexels-photo-97079.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Northwest Regional Council - Area Agency on Aging (NEMT Broker)', (SELECT id FROM resource_categories WHERE slug='transportation'), '', 'Northwest Regional Council (NWRC) is the Area Agency on Aging for Whatcom, Skagit, Island, and San Juan Counties, and is the HCA-contracted Non-Emergency Medical Transportation broker for those four counties. Arranges transportation for Medicaid/Apple Health clients to Medicaid-covered medical appointments using the lowest-cost appropriate mode (public transit, volunteer drivers, taxi, wheelchair van, mileage reimbursement). Also coordinates a broad range of aging and disability services for older adults and people with disabilities in the region. Whatcom direct: (360) 738-4554.', '600 W. Holly St.', 'Bellingham', 'Whatcom', 'WA', '98225', '1-800-860-6812', 'https://www.nwrcwa.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, false, false, false, false, false, true, false, true, 0, 0, '{English,Spanish}', '{wheelchair,ADA parking}', '{Northwest Regional Council (NWRC) is the Area Agency on Aging for Whatcom,Skagit,Island,and San Juan Counties,and is the HCA-contracted Non-Emergency Medical Transportation broker for those four counties}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/4488636/pexels-photo-4488636.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Special Mobility Services (SMS) - Medicaid NEMT Broker', (SELECT id FROM resource_categories WHERE slug='transportation'), '', 'HCA-contracted Medicaid Non-Emergency Medical Transportation broker for 11 Eastern Washington counties: Adams, Asotin, Ferry, Garfield, Grant, Lincoln, Pend Oreille, Spokane, Stevens, Whitman, and Garfield. Arranges the lowest-cost appropriate transportation (public transit, volunteer driver, taxi, wheelchair-accessible van, mileage/gas reimbursement, ferry/airfare when necessary) for Medicaid/Apple Health clients to covered medical appointments. Local: (509) 534-9760. TDD/TTY: 509-534-8566 or 800-821-7167.', '4101 S. Bonneville Blvd., Suite 200', 'Spokane', 'Spokane', 'WA', '99202', '1-800-892-4817', 'http://www.sms1.org/transportation', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, false, false, false, false, false, true, false, true, 0, 0, '{English,Spanish}', '{wheelchair,ADA parking}', '{HCA-contracted Medicaid Non-Emergency Medical Transportation broker for 11 Eastern Washington counties: Adams,Asotin,Ferry,Garfield,Grant}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/4488636/pexels-photo-4488636.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified') ON CONFLICT DO NOTHING;